import play.api.db.DBApi
import play.api.libs.json._
import play.api.mvc._

class OrderController(db: DBApi) extends Controller {

  def getOrder(orderId: Long) = Action.async { implicit request =>
    val order = db.run(Order.findById(orderId)).await()
    order match {
      case Some(o) => Ok(Json.toJson(o))
      case None => NotFound(Json.obj("message" -> "Order not found"))
    }
  }
}